class Solution:
    def maxPalindromes(self, s: str, k: int) -> int:
        n = len(s)
        dp = [0] * (n + 1)
        dp[n] = 0

        for i in range(n - 1, -1, -1):
            dp[i] = dp[i + 1]
            if i + k <= n:
                if s[i:i + k] == s[i:i + k][::-1]:
                    dp[i] = max(dp[i], 1 + dp[i + k])
                for j in range(i + k + 1, n + 1):
                    if s[i:j] == s[i:j][::-1]:
                        dp[i] = max(dp[i], 1 + dp[j])

        return dp[0]
